<template>
<div class="app-shell"><aside class="sidebar card"><div><div class="eyebrow">Campus Repair Console</div><h2>{{ roleLabel(authState.user?.role) }}</h2><p class="subtle">{{ authState.user?.realName }} · {{ authState.user?.username }}</p></div><nav class="nav-list"><button v-for="t in tabs" :key="t.key" class="nav-item" :class="{active:activeTab===t.key}" @click="activeTab=t.key"><span>{{ t.icon }}</span>{{ t.label }}</button></nav><button class="btn btn-ghost" @click="logout">退出登录</button></aside><main class="content-grid"><section class="hero card"><div><div class="eyebrow">Admin Hub</div><h1>管理员工作台</h1><p class="subtle">派单、人工确认、待分配、分类修正与规则配置闭环。</p></div></section><section class="card panel stack-lg"><div class="section-head"><h3>{{ currentTitle }}</h3><div class="cluster"><button class="btn btn-ghost" @click="loadAll">刷新</button><button v-if="activeTab==='dispatch'" class="btn btn-primary" @click="showPool=!showPool">{{ showPool?'收起维修池':'维修池' }}</button></div></div><div v-if="detail" class="detail-board"><div><span>工单号</span><strong>{{ detail.ticketNo }}</strong></div><div><span>状态</span><StatusPill :label="detail.status"/></div><div><span>位置</span><strong>{{ detail.locationText||'待解析' }}</strong></div><div><span>故障</span><strong>{{ detail.faultDesc||detail.rawText }}</strong></div><div><span>AI分类</span><strong>{{ categoryName(detail.categoryId) }}</strong></div></div><div v-if="activeTab==='dispatch'&&showPool" class="worker-pool"><div class="worker-pool__default" v-if="preferredWorkerId"><span>默认改派人</span><strong>{{ preferredWorkerName }}</strong></div><div class="worker-pool__grid"><article v-for="w in workers" :key="w.workerId" class="worker-card" :class="{'worker-card--selected':preferredWorkerId===w.workerId}"><strong>{{ w.workerName }}</strong><div class="worker-card__tags"><span>{{ w.skillTags }}</span><span>{{ w.serviceArea }}</span></div><div class="worker-card__metrics"><div><span>负载</span><strong>{{ w.currentLoad }}</strong></div><div><span>接单率</span><strong>{{ pct(w.acceptRate) }}</strong></div></div><button class="btn btn-ghost" @click="preferredWorkerId=preferredWorkerId===w.workerId?null:w.workerId">{{ preferredWorkerId===w.workerId?'取消默认改派人':'设为默认改派人' }}</button></article></div></div><div v-if="showTable" class="table-wrap"><table><thead><tr><th>工单号</th><th>状态</th><th>位置</th><th>故障</th><th>AI分类</th><th v-if="activeTab==='dispatch'">维修人</th><th v-if="activeTab==='categoryFix'">分类修正</th><th>操作</th></tr></thead><tbody><tr v-for="it in tableData" :key="it.ticketId"><td>{{ it.ticketNo }}</td><td><StatusPill :label="it.status"/></td><td>{{ it.locationText||'待解析' }}</td><td>{{ it.faultDesc||'待解析' }}</td><td>{{ categoryName(it.categoryId) }}</td><td v-if="activeTab==='dispatch'">{{ workerName(it.currentWorkerId) }}</td><td v-if="activeTab==='categoryFix'"><select v-model="categoryFixMap[it.ticketId]"><option value="">请选择</option><option v-for="c in categories" :key="c.categoryId" :value="c.categoryId">{{ c.categoryName }}</option></select></td><td><div class="action-grid"><button class="btn btn-ghost" @click="viewTicket(it.ticketId)">详情</button><button v-if="activeTab==='dispatch'&&it.status==='待受理'" class="btn btn-primary" @click="parseTicket(it.ticketId)">解析</button><button v-if="(activeTab==='dispatch'||activeTab==='pendingPool')&&['已解析','待分配'].includes(it.status)" class="btn btn-primary" @click="autoDispatch(it.ticketId)">自动派单</button><button v-if="(activeTab==='dispatch'||activeTab==='pendingPool')&&['已解析','待分配','已派单'].includes(it.status)" class="btn btn-ghost" @click="manualDispatch(it.ticketId)">改派</button><button v-if="activeTab==='categoryFix'" class="btn btn-primary" @click="correctCategory(it.ticketId)">提交修正</button></div></td></tr></tbody></table></div><div v-if="activeTab==='reviewQueue'" class="table-wrap"><table><thead><tr><th>工单号</th><th>原始文本</th><th>原因</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="q in reviewQueue" :key="q.id"><td>{{ q.ticketNo }}</td><td>{{ q.rawText }}</td><td>{{ q.reason }}</td><td><StatusPill :label="q.queueStatus"/></td><td><div class="action-grid"><button class="btn btn-primary" @click="confirmQueue(q)">人工补录</button></div></td></tr></tbody></table></div><div v-if="activeTab==='rules'" class="stack-lg"><div class="rule-hero"><div><div class="eyebrow">Dispatch Rule</div><h4>派单权重配置</h4><p class="subtle">仅展示当前可编辑的派单权重，并基于实际配置进行保存或重算。</p></div></div><div class="rule-grid"><article v-for="item in weightItems" :key="item.key" class="rule-card"><div class="rule-card__head"><strong>{{ item.label }}</strong><span>{{ (item.value*100).toFixed(0) }}%</span></div><input v-model.number="ruleForm[item.key]" type="range" min="0" max="1" step="0.01"/><input v-model.number="ruleForm[item.key]" type="number" min="0" max="1" step="0.01"/></article></div><div class="cluster"><span class="subtle">建议保持总和为 1。技能、区域、负载决定基础匹配；绩效与紧急度用于精细调度。</span><button class="btn btn-primary" @click="saveWeights">保存</button><button class="btn btn-ghost" @click="recalculate">基于反馈重算</button></div></div><div v-if="activeTab==='stats'" class="stats-visual"><div class="stats-kpi-grid"><article class="kpi-card"><span>派单总量</span><strong>{{ latestSnapshot?.dispatchCount ?? 0 }}</strong><small>统计窗口总派单次数</small></article><article class="kpi-card"><span>改派率</span><strong>{{ latestSnapshot ? pctNum(latestSnapshot.reassignRate) : '-' }}</strong><small>人工改派占比</small></article><article class="kpi-card"><span>拒单率</span><strong>{{ latestSnapshot ? pctNum(latestSnapshot.rejectRate) : '-' }}</strong><small>维修人员拒单占比</small></article><article class="kpi-card"><span>超时率</span><strong>{{ latestSnapshot ? pctNum(latestSnapshot.timeoutRate) : '-' }}</strong><small>超 24h 完工占比</small></article><article class="kpi-card"><span>平均完工</span><strong>{{ latestSnapshot?.avgCompleteHours ?? '-' }}h</strong><small>统计窗口平均完工时长</small></article></div><div class="dashboard-columns"><div class="mini-panel"><h4>分类分布</h4><div class="bar-list"><div v-for="i in categoryStats" :key="i.name" class="bar-item"><div class="bar-item__head"><span>{{ i.name }}</span><strong>{{ i.count }}</strong></div><div class="bar-track"><div class="bar-fill" :style="{width:barWidth(i.count,categoryMax)}"></div></div></div></div></div><div class="mini-panel"><h4>维修负载</h4><div class="bar-list"><div v-for="i in workerLoad" :key="i.workerId" class="bar-item"><div class="bar-item__head"><span>{{ i.workerName }}</span><strong>{{ i.count }}</strong></div><div class="bar-track bar-track--warm"><div class="bar-fill bar-fill--warm" :style="{width:barWidth(i.count,workerMax)}"></div></div></div></div></div><div class="mini-panel"><h4>权重结构</h4><div class="weight-ring-list"><div v-for="item in weightItems" :key="item.key" class="weight-line"><span>{{ item.label }}</span><div class="bar-track"><div class="bar-fill bar-fill--cyan" :style="{width:(item.value*100)+'%'}"></div></div><strong>{{ (item.value*100).toFixed(0) }}%</strong></div></div></div></div></div><p v-if="fb.global" class="feedback feedback-success">{{ fb.global }}</p><p v-if="fb.error" class="feedback feedback-error">{{ fb.error }}</p></section></main></div>
</template>
<script setup>
import {computed,onMounted,reactive,ref} from 'vue'
import {useRouter} from 'vue-router'
import http,{unwrap} from '../api'
import {authState,clearAuth} from '../store/auth'
import {roleLabel} from '../utils'
import StatusPill from './StatusPill.vue'
const router=useRouter(),activeTab=ref('dispatch'),tickets=ref([]),pendingPool=ref([]),workers=ref([]),reviewQueue=ref([]),categories=ref([]),detail=ref(null),overview=ref(null),categoryStats=ref([]),workerLoad=ref([]),showPool=ref(false),preferredWorkerId=ref(null)
const manualConfirmDraft=reactive({locationText:'',faultDesc:'',urgencyLevel:'MEDIUM',categoryId:''})
const tabs=[{key:'dispatch',label:'派单监控',icon:'◎'},{key:'pendingPool',label:'待分配池',icon:'◍'},{key:'reviewQueue',label:'人工确认',icon:'◌'},{key:'categoryFix',label:'分类修正',icon:'◫'},{key:'rules',label:'规则配置',icon:'⚙'},{key:'stats',label:'统计看板',icon:'▣'}]
const fb=reactive({global:'',error:''}),categoryFixMap=reactive({}),ruleForm=reactive({weightSkill:.35,weightArea:.2,weightLoad:.2,weightPerf:.1,weightUrgency:.15})
const currentTitle=computed(()=>tabs.find(i=>i.key===activeTab.value)?.label||''),tableData=computed(()=>activeTab.value==='pendingPool'?pendingPool.value:tickets.value),showTable=computed(()=>['dispatch','pendingPool','categoryFix'].includes(activeTab.value)),preferredWorkerName=computed(()=>workers.value.find(i=>i.workerId===preferredWorkerId.value)?.workerName||`#${preferredWorkerId.value}`),latestSnapshot=computed(()=>overview.value?.latestSnapshot||null),weightItems=computed(()=>[{label:'技能匹配',key:'weightSkill',value:Number(ruleForm.weightSkill||0)},{label:'服务区域',key:'weightArea',value:Number(ruleForm.weightArea||0)},{label:'任务负载',key:'weightLoad',value:Number(ruleForm.weightLoad||0)},{label:'历史绩效',key:'weightPerf',value:Number(ruleForm.weightPerf||0)},{label:'紧急程度',key:'weightUrgency',value:Number(ruleForm.weightUrgency||0)}]),categoryMax=computed(()=>Math.max(1,...categoryStats.value.map(i=>Number(i.count)||0))),workerMax=computed(()=>Math.max(1,...workerLoad.value.map(i=>Number(i.count)||0)))
const reset=()=>{fb.global='';fb.error=''},logout=()=>{clearAuth();router.push('/login')},pct=v=>v==null?'-':`${Math.round(Number(v)*100)}%`,pctNum=v=>`${Math.round(Number(v||0)*100)}%`,workerName=id=>workers.value.find(i=>i.workerId===id)?.workerName||(id?`#${id}`:'未指派'),categoryName=id=>categories.value.find(i=>i.categoryId===id)?.categoryName||(id?`#${id}`:'未分类'),barWidth=(count,max)=>`${Math.max(8,Math.round((Number(count||0)/Math.max(1,max))*100))}%`
async function run(task,msg=''){reset();try{await task();if(msg)fb.global=msg}catch(e){fb.error=e.message||'操作失败'}}
async function loadAll(){tickets.value=unwrap(await http.get('/admin/tickets?page=1&size=50')).records||[];workers.value=unwrap(await http.get('/admin/workers'));categories.value=unwrap(await http.get('/admin/categories'));await loadPendingPool();await loadRules()}
async function loadPendingPool(){pendingPool.value=unwrap(await http.get(`/admin/tickets?page=1&size=20&status=${encodeURIComponent('待分配')}`)).records||[]}
async function loadReviewQueue(){reviewQueue.value=unwrap(await http.get('/admin/llm/review-queue?page=1&size=20')).records||[]}
async function loadRules(){overview.value=unwrap(await http.get('/admin/dispatch-feedback'));categoryStats.value=unwrap(await http.get('/admin/stats/category-distribution'));workerLoad.value=unwrap(await http.get('/admin/stats/worker-load'));const activeWeight=overview.value?.activeWeight;if(activeWeight){ruleForm.weightSkill=Number(activeWeight.weightSkill??0);ruleForm.weightArea=Number(activeWeight.weightArea??0);ruleForm.weightLoad=Number(activeWeight.weightLoad??0);ruleForm.weightPerf=Number(activeWeight.weightPerf??0);ruleForm.weightUrgency=Number(activeWeight.weightUrgency??0)}}
async function viewTicket(id){await run(async()=>{detail.value=unwrap(await http.get(`/tickets/${id}`))})}
async function parseTicket(id){await run(async()=>{await http.post('/llm/parse',{ticketId:id});await loadAll();await loadReviewQueue();await viewTicket(id)},'LLM解析完成')}
async function autoDispatch(id){await run(async()=>{await http.post(`/tickets/${id}/dispatch/auto`);await loadAll();await viewTicket(id)},'自动派单已执行')}
async function manualDispatch(id){const txt=workers.value.map(i=>`${i.workerId}:${i.workerName}`).join('\n');const v=window.prompt(`输入 workerId:\n${txt}`,preferredWorkerId.value||workers.value[0]?.workerId||'');if(!v)return;await run(async()=>{await http.post(`/tickets/${id}/dispatch/manual`,{workerId:Number(v),reason:'管理员人工改派'});preferredWorkerId.value=Number(v);await loadAll();await viewTicket(id)},'人工改派成功')}
async function confirmQueue(q){manualConfirmDraft.locationText=q.rawText||'';manualConfirmDraft.faultDesc='';manualConfirmDraft.urgencyLevel='MEDIUM';manualConfirmDraft.categoryId=categories.value[0]?.categoryId||'';const locationText=window.prompt('请输入位置',manualConfirmDraft.locationText);if(locationText===null)return;const faultDesc=window.prompt('请输入故障描述',manualConfirmDraft.faultDesc||q.rawText||'');if(faultDesc===null)return;const urgencyLevel=window.prompt('请输入紧急度（LOW/MEDIUM/HIGH）',manualConfirmDraft.urgencyLevel);if(urgencyLevel===null)return;const cid=window.prompt(`输入分类ID:\n${categories.value.map(i=>`${i.categoryId}:${i.categoryName}`).join('\n')}`,manualConfirmDraft.categoryId||'');if(cid===null)return;await run(async()=>{await http.post(`/admin/llm/review-queue/${q.id}/confirm`,{locationText:String(locationText).trim(),faultDesc:String(faultDesc).trim(),urgencyLevel:String(urgencyLevel).trim().toUpperCase(),categoryId:Number(cid)});await loadAll();await loadReviewQueue()},'人工确认已完成')}
async function correctCategory(id){if(!categoryFixMap[id])return fb.error='请选择分类';await run(async()=>{await http.post(`/admin/tickets/${id}/category`,{categoryId:Number(categoryFixMap[id]),reason:'管理员前端修正'});await loadAll();await viewTicket(id)},'分类修正已提交')}
async function saveWeights(){const sum=Number(ruleForm.weightSkill||0)+Number(ruleForm.weightArea||0)+Number(ruleForm.weightLoad||0)+Number(ruleForm.weightPerf||0)+Number(ruleForm.weightUrgency||0);if(Math.abs(sum-1)>0.001)return fb.error='权重之和必须为1';await run(async()=>{overview.value=unwrap(await http.post('/admin/dispatch-feedback/weights',{...ruleForm}));await loadRules()},'规则权重已更新')}
async function recalculate(){await run(async()=>{overview.value=unwrap(await http.post('/admin/dispatch-feedback/recalculate'));await loadRules()},'派单反馈权重已重算')}
onMounted(async()=>{await loadAll();await loadReviewQueue()})
</script>
